const fs = require('fs');
const path = require('path');

// Load problems data from JSON file
const problemsDataPath = path.resolve(__dirname, '../../data/problems.json');
let problems = [];
try {
  const rawData = fs.readFileSync(problemsDataPath, 'utf8');
  problems = JSON.parse(rawData);
} catch (e) {
  problems = [];
}

/**
 * List problems with filtering, paging, and metadata.
 * @param {Object} options
 * @param {string} [options.difficulty] - Filter by difficulty (e.g. 'Easy', 'Medium', 'Hard')
 * @param {number} [options.limit=50] - Max number of results to return (max 50)
 * @param {boolean} [options.includeComponents=false] - Whether to include componentLanguages sorted
 * @returns {Object} result with problems array and metadata
 */
function solve(options = {}) {
  const difficultyFilter = options.difficulty;
  let limit = options.limit === undefined ? 50 : options.limit;
  if (typeof limit !== 'number' || limit <= 0) limit = 50;
  if (limit > 50) limit = 50;
  const includeComponents = options.includeComponents === true;

  const totalProblems = problems.length;

  // Filter by difficulty if specified
  let filtered = difficultyFilter
    ? problems.filter(p => p.difficulty === difficultyFilter)
    : problems.slice();

  const filteredCount = filtered.length;

  // Sort by roundId ascending for deterministic ordering
  filtered.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  // Apply limit
  const limited = filtered.slice(0, limit);

  // Prepare difficulty breakdown for filtered set
  const difficultyBreakdown = {};
  for (const p of filtered) {
    difficultyBreakdown[p.difficulty] = (difficultyBreakdown[p.difficulty] || 0) + 1;
  }

  // Prepare problems output
  const outputProblems = limited.map(p => {
    const problemCopy = {
      ...p,
    };
    if (includeComponents && Array.isArray(problemCopy.componentLanguages)) {
      problemCopy.componentLanguages = problemCopy.componentLanguages.slice().sort();
    } else {
      delete problemCopy.componentLanguages;
    }
    return problemCopy;
